/// Manufacturing module configuration
///
/// Use the builder pattern to configure and register this module:
///
/// ```text
/// let manufacturing = ManufacturingModule::builder()
///     .with_database(pool.clone())
///     .build()?;
///
/// // Unguarded full CRUD (trusted/admin); compose a guarded router for production.
/// let router = manufacturing.all_crud_routes();
/// ```
pub struct ManufacturingModule {
    pub workstation_service: Arc<WorkstationService>,
    pub operation_service: Arc<OperationService>,
    pub bom_service: Arc<BomService>,
    pub bom_item_service: Arc<BomItemService>,
    pub bom_operation_service: Arc<BomOperationService>,
    pub work_order_service: Arc<WorkOrderService>,
    pub work_order_item_service: Arc<WorkOrderItemService>,
    pub job_card_service: Arc<JobCardService>,
}

impl ManufacturingModule {
    /// Create a new module builder
    pub fn builder() -> ManufacturingModuleBuilder {
        ManufacturingModuleBuilder::new()
    }

    /// Mount ALL generated CRUD endpoints (12 per entity) with NO domain
    /// validation — the fully **unguarded** surface. A well-formed request can
    /// create invalid rows or soft-delete a referenced master out from under its
    /// dependents. Prefer a guarded composition (read + validated writes) for any
    /// real deployment; use this only in trusted/admin/seeding contexts.
    pub fn all_crud_routes(&self) -> Router {
        use presentation::http::{
            create_workstation_routes,
            create_operation_routes,
            create_bom_routes,
            create_bom_item_routes,
            create_bom_operation_routes,
            create_work_order_routes,
            create_work_order_item_routes,
            create_job_card_routes,
        };

        Router::new()
            .merge(create_workstation_routes(self.workstation_service.clone()))
            .merge(create_operation_routes(self.operation_service.clone()))
            .merge(create_bom_routes(self.bom_service.clone()))
            .merge(create_bom_item_routes(self.bom_item_service.clone()))
            .merge(create_bom_operation_routes(self.bom_operation_service.clone()))
            .merge(create_work_order_routes(self.work_order_service.clone()))
            .merge(create_work_order_item_routes(self.work_order_item_service.clone()))
            .merge(create_job_card_routes(self.job_card_service.clone()))
    }

    /// Deprecated alias for [`Self::all_crud_routes`]. `routes()` reads like
    /// "the routes" but mounts UNVALIDATED generic CRUD on every entity — a naive
    /// mount exposes unguarded writes. Compose a guarded router (read + validated
    /// writes) for production, or call `all_crud_routes()` to opt into the full
    /// unguarded surface explicitly.
    #[deprecated(note = "mounts unvalidated generic CRUD on every entity; compose a guarded router for production, or call all_crud_routes() for the intentional full/unguarded surface")]
    pub fn routes(&self) -> Router {
        self.all_crud_routes()
    }
}

